oxy_webhelp_navlinks = {"github-d27248e32403":{"topics":[{"title":"Introduction to GitHub","href":"github\/github_protection_key_feature.html","menu":{"hasChildren":false},"tocID":"tocId-d27248e32416","next":"tocId-d27248e32416"},{"title":"High-level implementation workflow for GitHub","shortdesc":"<p class=\"shortdesc\">The GitHub protection implementation workflow involves a structured approach to         secure data management, starting with planning and preparation, followed by GitHub         organization setup, GitHub protection, continuous management and optimization, and         repository recovery.<\/p>","href":"github\/github_high_level_implement_workflow.html","attributes":{"data-id":"github_high_level_implement_workflow"},"menu":{"hasChildren":false},"tocID":"github_high_level_implement_workflow-d27248e32475","topics":[]},{"title":"Quick links for GitHub","shortdesc":"<p class=\"shortdesc\">Immediate access to important tasks and information, enabling quick setup, daily         operations, and critical recovery.<\/p>","href":"github\/github_quick_links.html","attributes":{"data-id":"github_quick_links"},"menu":{"hasChildren":false},"tocID":"github_quick_links-d27248e32486","topics":[]},{"title":"Plan your GitHub protection","shortdesc":"<p class=\"shortdesc\">Before setting up a GitHub organization in <span class=\"ph\">RSC<\/span>, you need to plan user         and access management for designated <span class=\"ph\">RSC<\/span> users. This involves reviewing the         permissions that <span class=\"ph\">RSC<\/span> requires for GitHub, as well as in your Azure or AWS         cloud provider, to install Exocompute and create storage accounts for protecting GitHub         organizations.<\/p>","href":"github\/github_plan_protection.html","attributes":{"data-id":"github_plan_protection"},"menu":{"hasChildren":false},"tocID":"github_plan_protection-d27248e32497","next":"github_plan_protection-d27248e32497"},{"title":"Set up GitHub organization","shortdesc":"<p class=\"shortdesc\">You can add a GitHub organization in <span class=\"ph\">RSC<\/span> to start protecting GitHub         resources.<\/p>","href":"github\/github_setup_organization.html","attributes":{"data-id":"github_setup_organization"},"menu":{"hasChildren":false},"tocID":"github_setup_organization-d27248e32623","next":"github_setup_organization-d27248e32623"},{"title":"Set up protection for GitHub","shortdesc":"<p class=\"shortdesc\">You can set up SLA Domains to apply data protection policies, ensuring automatic and         hierarchical protection of GitHub organizations and repositories, with granular control         overriding higher-level assignments.<\/p>","href":"github\/github_set_up_protection.html","attributes":{"data-id":"github_set_up_protection"},"menu":{"hasChildren":false},"tocID":"github_set_up_protection-d27248e32880","next":"github_set_up_protection-d27248e32880"},{"title":"Manage GitHub organizations and repositories","shortdesc":"<p class=\"shortdesc\">After completing the protection setup for GitHub organizations and repositories, <span class=\"ph\">RSC<\/span> takes automated snapshots of those repositories based on the configured         policies in SLA Domains. You can also take on-demand snapshots and refresh GitHub         organizations for better resource management.<\/p>","href":"github\/github_manage_orgs_repos.html","attributes":{"data-id":"github_manage_orgs_repos"},"menu":{"hasChildren":false},"tocID":"github_manage_orgs_repos-d27248e32995","next":"github_manage_orgs_repos-d27248e32995"},{"title":"Recover GitHub","shortdesc":"<p class=\"shortdesc\">After <span class=\"ph\">RSC<\/span> takes snapshots of your GitHub repositories, you can         recover the necessary details.<\/p>","href":"github\/github_recover.html","attributes":{"data-id":"github_recover"},"menu":{"hasChildren":false},"tocID":"github_recover-d27248e33069","next":"github_recover-d27248e33069"},{"title":"Access GitHub reports","shortdesc":"<p class=\"shortdesc\">With <span class=\"ph\">RSC<\/span>, you can create and download reports based on templates to         monitor the protection status of your GitHub organizations and repositories.<\/p>","href":"github\/github_access_reports.html","attributes":{"data-id":"github_access_reports"},"menu":{"hasChildren":false},"tocID":"github_access_reports-d27248e33107","next":"github_access_reports-d27248e33107"}]}};